                ["SetupComponentsNote"] = "AIHelper \u0434\u0435\u043b\u0430\u0435\u0442 DNS-\u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u044f\u0432\u043d\u044b\u043c\u0438 \u0438 \u043e\u0431\u0440\u0430\u0442\u0438\u043c\u044b\u043c\u0438. \u0411\u0430\u0437\u043e\u0432\u044b\u0435 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u044b \u0432\u0440\u043e\u0434\u0435 winget, Node.js, npm \u0438 Git \u043f\u0440\u043e\u0432\u0435\u0440\u044f\u044e\u0442\u0441\u044f \u0441\u043b\u0435\u0432\u0430.",
                ["SetupComponentsActionHint"] = "NPM \u0441\u0442\u0430\u0432\u0438\u0442\u0441\u044f \u0432\u043c\u0435\u0441\u0442\u0435 \u0441 Node.js. \u0415\u0441\u043b\u0438 winget \u043e\u0442\u0441\u0443\u0442\u0441\u0442\u0432\u0443\u0435\u0442, \u0441\u043d\u0430\u0447\u0430\u043b\u0430 \u0432\u043e\u0441\u0441\u0442\u0430\u043d\u043e\u0432\u0438 App Installer, \u0430 \u043f\u043e\u0442\u043e\u043c \u0437\u0430\u043f\u0443\u0441\u0442\u0438 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0443 \u0431\u0430\u0437\u043e\u0432\u044b\u0445 \u0438\u043d\u0441\u0442\u0440\u0443\u043c\u0435\u043d\u0442\u043e\u0432.",
                ["SetupInstallNoteTitle"] = "\u0427\u0442\u043e \u0434\u0435\u043b\u0430\u0435\u0442 installer",
                ["SetupInstallNote"] = "\u041e\u0442\u043a\u0440\u044b\u0432\u0430\u0435\u0442 elevated PowerShell, \u043a\u043e\u0442\u043e\u0440\u044b\u0439 \u0441\u0442\u0430\u0432\u0438\u0442 \u0438\u043b\u0438 \u043e\u0431\u043d\u043e\u0432\u043b\u044f\u0435\u0442 Node.js LTS \u0438 Git \u0447\u0435\u0440\u0435\u0437 winget, \u0430 \u0437\u0430\u0442\u0435\u043c \u0441\u0442\u0430\u0432\u0438\u0442 @openai/codex \u0433\u043b\u043e\u0431\u0430\u043b\u044c\u043d\u043e \u0447\u0435\u0440\u0435\u0437 npm.",
                ["SetupLocalAiTitle"] = "3. \u041b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0435 \u043d\u0435\u0439\u0440\u043e\u0441\u0435\u0442\u0438",
                ["SetupLocalAiSubtitle"] = "Ставьте бесплатные локальные runtime-ы, текстовые модели и creative AI-приложения для офлайн- и privacy-сценариев.",
                ["SetupInstallOllamaButton"] = "\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c / repair Ollama",
                ["SetupInstallLmStudioButton"] = "\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u0438\u0442\u044c / repair LM Studio",
                ["SetupUninstallOllamaButton"] = "\u0423\u0434\u0430\u043b\u0438\u0442\u044c Ollama",
                ["SetupUninstallLmStudioButton"] = "\u0423\u0434\u0430\u043b\u0438\u0442\u044c LM Studio",
                ["SetupLocalAiModelsTitle"] = "Текстовые модели для Ollama",
                ["SetupLocalAiModelsSubtitle"] = "Эти кнопки через Ollama ставят или удаляют готовые локальные языковые модели в Windows. Сначала нужно поставить Ollama.",
                ["SetupInstallModelButton"] = "\u0421\u0442\u0430\u0432\u0438\u0442\u044c \u0447\u0435\u0440\u0435\u0437 Ollama",
                ["SetupRemoveModelButton"] = "\u0423\u0434\u0430\u043b\u0438\u0442\u044c \u043c\u043e\u0434\u0435\u043b\u044c",
                ["SetupLocalAiModelsNote"] = "\u0421\u043a\u0430\u0447\u0438\u0432\u0430\u043d\u0438\u0435 \u043c\u043e\u0434\u0435\u043b\u0435\u0439 \u043c\u043e\u0436\u0435\u0442 \u0437\u0430\u043d\u044f\u0442\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u043c\u0438\u043d\u0443\u0442 \u0438 \u0437\u0430\u043d\u044f\u0442\u044c \u043d\u0435\u0441\u043a\u043e\u043b\u044c\u043a\u043e \u0433\u0438\u0433\u0430\u0431\u0430\u0439\u0442 \u043d\u0430 \u0434\u0438\u0441\u043a\u0435.",
                ["SetupCreativeAiTitle"] = "Генерация изображений, видео и 3D",
                ["SetupCreativeAiSubtitle"] = "Ставьте бесплатные локальные creative AI-приложения для генерации изображений, видео-пайплайнов и 3D-экспериментов на Windows.",
                ["SetupInstallCreativeToolButton"] = "Установить приложение",
                ["SetupRemoveCreativeToolButton"] = "Удалить приложение",
                ["SetupCreativeAiNote"] = "После первого запуска эти приложения могут скачивать дополнительные модели. Требования к GPU, VRAM и диску зависят от выбранного workflow или приложения внутри них.",
                ["SetupCreativeAiCoverageUniversal"] = "Изображения / Видео / 3D",
                ["SetupCreativeAiCoverageLauncher"] = "Лаунчер AI-приложений",
                ["SetupCreativeAiMissingDetail"] = "Пока не установлено. AIHelper может поставить или удалить это приложение через winget.",
                ["SetupCreativeAiToolComfyDescription"] = "Официальное десктопное приложение ComfyUI со встроенными Manager и uv. Подходит для локальных workflow по изображениям, видео и 3D на одном ПК.",
                ["SetupCreativeAiToolPinokioDescription"] = "Лаунчер для скриптуемых установок локальных AI-приложений. Удобен как второй desktop-инструмент для экспериментов с изображениями, видео и 3D.",
                ["SetupAiAgentsTitle"] = "AI-агенты",
                ["SetupAiAgentsSubtitle"] = "Ставьте локальные agent-инструменты, которые умеют оркестрировать задачи и работать в несколько шагов на вашем ПК.",
                ["SetupInstallAiAgentButton"] = "Установить агент",
                ["SetupRemoveAiAgentButton"] = "Удалить агент",
                ["SetupAiAgentsNote"] = "AIHelper ставит OpenClaw через npm и затем запускает onboard в видимом терминале. Для этого уже должны быть установлены Node.js 22+, npm и Git. На первом этапе npm несколько минут может почти ничего не выводить.",
                ["SetupAiAgentCoverageLocal"] = "Локальный AI-агент",
                ["SetupAiAgentMissingDetail"] = "Пока не установлен. AIHelper может поставить OpenClaw через npm, при необходимости поправить PATH и запустить onboard в видимом терминале. Git должен быть установлен заранее.",
                ["SetupAiAgentOpenClawDescription"] = "Локальный agent-инструмент OpenClaw, который ставится через npm и затем запускает видимый onboard-этап. Требует Node.js 22+, npm и Git. Подходит, если нужен отдельный AI-агент вне Codex.",
                ["SetupLocalAiModelCoderDescription"] = "\u041a\u043e\u0434\u0435\u0440\u0441\u043a\u0430\u044f open-source \u043c\u043e\u0434\u0435\u043b\u044c \u0434\u043b\u044f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u044b \u0441 \u043a\u043e\u0434\u043e\u043c \u0438 \u0440\u0435\u043f\u043e\u0437\u0438\u0442\u043e\u0440\u0438\u044f\u043c\u0438.",
                ["SetupLocalAiModelReasoningDescription"] = "\u041b\u0451\u0433\u043a\u0430\u044f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u0430\u044f reasoning-\u043c\u043e\u0434\u0435\u043b\u044c, \u043a\u043e\u0442\u043e\u0440\u0443\u044e \u043f\u0440\u043e\u0449\u0435 \u0437\u0430\u043f\u0443\u0441\u0442\u0438\u0442\u044c \u043d\u0430 \u043e\u0431\u044b\u0447\u043d\u044b\u0445 \u043d\u043e\u0443\u0442\u0431\u0443\u043a\u0430\u0445.",
                ["SetupLocalAiModelGeneralDescription"] = "\u0421\u0431\u0430\u043b\u0430\u043d\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u0430\u044f \u043c\u043e\u0434\u0435\u043b\u044c \u0434\u043b\u044f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0433\u043e \u0447\u0430\u0442\u0430, \u0442\u0435\u043a\u0441\u0442\u043e\u0432 \u0438 \u043f\u043e\u0432\u0441\u0435\u0434\u043d\u0435\u0432\u043d\u044b\u0445 \u0437\u0430\u0434\u0430\u0447.",
                ["SetupLocalAiInstalled"] = "\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0430",
                ["SetupLocalAiNotInstalled"] = "\u041d\u0435 \u0443\u0441\u0442\u0430\u043d\u043e\u0432\u043b\u0435\u043d\u0430",
                ["SetupLocalAiInstalledSize"] = "\u0420\u0430\u0437\u043c\u0435\u0440 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e: {0}",
                ["SetupLocalAiMissingSize"] = "\u042d\u0442\u0430 \u043c\u043e\u0434\u0435\u043b\u044c \u0435\u0449\u0451 \u043d\u0435 \u0445\u0440\u0430\u043d\u0438\u0442\u0441\u044f \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e.",
                ["SetupNetworkTitle"] = "\u041f\u0440\u043e\u0437\u0440\u0430\u0447\u043d\u043e\u0441\u0442\u044c",
                ["SetupNetworkNote"] = "\u0418\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u044e\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u043a \u0432\u044b\u0431\u0440\u0430\u043d\u043d\u043e\u043c\u0443 \u0430\u0434\u0430\u043f\u0442\u0435\u0440\u0443 Windows. \u041f\u0435\u0440\u0435\u0434 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435\u043c AIHelper \u0441\u043e\u0445\u0440\u0430\u043d\u044f\u0435\u0442 \u0442\u0435\u043a\u0443\u0449\u0438\u0435 DNS-\u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438, \u0447\u0442\u043e\u0431\u044b \u043c\u043e\u0436\u043d\u043e \u0431\u044b\u043b\u043e \u0432\u0435\u0440\u043d\u0443\u0442\u044c auto-DNS \u0438\u043b\u0438 \u043e\u0442\u043a\u0430\u0442\u0438\u0442\u044c \u043f\u0440\u0435\u0434\u044b\u0434\u0443\u0449\u0438\u0435 \u0437\u043d\u0430\u0447\u0435\u043d\u0438\u044f.",
                ["SettingsTitle"] = "\u041d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438",
                ["SettingsSubtitle"] = "\u0423\u043f\u0440\u0430\u0432\u043b\u044f\u0439\u0442\u0435 \u043f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u0430\u043c\u0438 AIHelper, \u043f\u043e\u0432\u0435\u0434\u0435\u043d\u0438\u0435\u043c \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 \u0438 \u043e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u0438\u044f\u043c\u0438.",
                ["SettingsGeneralTitle"] = "\u041e\u0431\u0449\u0438\u0435 \u043f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u044b",
                ["SettingsGeneralSubtitle"] = "\u042d\u0442\u0438 \u043d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438 \u0432\u043b\u0438\u044f\u044e\u0442 \u043d\u0430 AIHelper \u0438 \u043d\u0430 \u0441\u0442\u0430\u0440\u0442\u043e\u0432\u044b\u0435 \u043f\u0430\u0440\u0430\u043c\u0435\u0442\u0440\u044b \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 Codex.",
                ["SettingsLanguageTitle"] = "\u042f\u0437\u044b\u043a \u0438\u043d\u0442\u0435\u0440\u0444\u0435\u0439\u0441\u0430",
                ["SettingsLanguageHelp"] = "\u0412\u044b\u0431\u0440\u0430\u043d\u043d\u044b\u0439 \u044f\u0437\u044b\u043a \u043f\u0440\u0438\u043c\u0435\u043d\u044f\u0435\u0442\u0441\u044f \u0441\u0440\u0430\u0437\u0443 \u043a\u043e \u0432\u0441\u0435\u043c\u0443 \u043f\u0440\u0438\u043b\u043e\u0436\u0435\u043d\u0438\u044e.",
                ["SettingsDangerousAccessTitle"] = "\u041f\u043e\u043b\u043d\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e",
                ["SettingsDangerousAccessHelp"] = "\u0415\u0441\u043b\u0438 \u0432\u043a\u043b\u044e\u0447\u0438\u0442\u044c \u044d\u0442\u0443 \u043e\u043f\u0446\u0438\u044e, AIHelper \u0431\u0443\u0434\u0435\u0442 \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u044f\u0442\u044c \u0434\u043b\u044f \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 danger-full-access \u0438 \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0443 never. \u0412\u043a\u043b\u044e\u0447\u0430\u0439\u0442\u0435 \u0442\u043e\u043b\u044c\u043a\u043e \u0435\u0441\u043b\u0438 \u043f\u043e\u043b\u043d\u043e\u0441\u0442\u044c\u044e \u0434\u043e\u0432\u0435\u0440\u044f\u0435\u0442\u0435 \u0441\u0435\u0441\u0441\u0438\u0438.",
                ["SettingsDangerousAccessToggle"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u043f\u043e\u043b\u043d\u044b\u0439 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f \u043a\u0430\u043a \u0434\u0435\u0444\u043e\u043b\u0442 \u0434\u043b\u044f \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439",
                ["SettingsDangerousAccessApplyButton"] = "\u041f\u0440\u0438\u043c\u0435\u043d\u0438\u0442\u044c \u0440\u0435\u0436\u0438\u043c \u0434\u043e\u0441\u0442\u0443\u043f\u0430",
                ["SettingsDangerousAccessWarningTitle"] = "\u0412\u043a\u043b\u044e\u0447\u0435\u043d\u0438\u0435 \u043f\u043e\u043b\u043d\u043e\u0433\u043e \u0434\u043e\u0441\u0442\u0443\u043f\u0430",
                ["SettingsDangerousAccessWarningMessage"] = "\u0412\u044b \u0441\u043e\u0431\u0438\u0440\u0430\u0435\u0442\u0435\u0441\u044c \u0441\u0434\u0435\u043b\u0430\u0442\u044c \u043f\u043e\u043b\u043d\u044b\u0439 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f \u0434\u0435\u0444\u043e\u043b\u0442\u043e\u043c \u0434\u043b\u044f \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439 Codex.\n\nCodex \u043f\u043e\u043b\u0443\u0447\u0438\u0442 danger-full-access \u0438 \u043f\u043e\u043b\u0438\u0442\u0438\u043a\u0443 never. \u042d\u0442\u043e \u043c\u043e\u0436\u0435\u0442 \u0434\u0430\u0442\u044c \u043d\u0435\u043e\u0433\u0440\u0430\u043d\u0438\u0447\u0435\u043d\u043d\u043e\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u0435 \u0444\u0430\u0439\u043b\u043e\u0432 \u0438 \u0437\u0430\u043f\u0443\u0441\u043a \u043a\u043e\u043c\u0430\u043d\u0434 \u0431\u0435\u0437 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u0432.\n\n\u041f\u0440\u043e\u0434\u043e\u043b\u0436\u0438\u0442\u044c?",
                ["SettingsStatusReady"] = "\u041d\u0430\u0441\u0442\u0440\u043e\u0439\u043a\u0438 \u0433\u043e\u0442\u043e\u0432\u044b.",
                ["SettingsStatusDangerousEnabled"] = "\u041f\u043e\u043b\u043d\u044b\u0439 \u0434\u043e\u0441\u0442\u0443\u043f \u0442\u0435\u043f\u0435\u0440\u044c \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u043f\u043e \u0443\u043c\u043e\u043b\u0447\u0430\u043d\u0438\u044e \u0434\u043b\u044f \u043d\u043e\u0432\u044b\u0445 \u0441\u0435\u0441\u0441\u0438\u0439.",
