    private AppLanguage _currentLanguage = AppLanguage.English;

    public event PropertyChangedEventHandler? PropertyChanged;

    public AppLanguage CurrentLanguage => _currentLanguage;

    public string this[string key]
    {
        get
        {
            var languageMap = Translations[_currentLanguage];
            return languageMap.TryGetValue(key, out var value) ? value : key;
        }
    }

    public string Format(string key, params object[] args)
    {
        return string.Format(this[key], args);
    }

    public void SetLanguage(AppLanguage language)
    {
        if (_currentLanguage == language)
        {
            return;
        }

        _currentLanguage = language;
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs(nameof(CurrentLanguage)));
        PropertyChanged?.Invoke(this, new PropertyChangedEventArgs("Item[]"));
    }
